   403→	}
   404→
   405→	sources := map[ulid.ULID]struct{}{}
   406→	mint := blocks[0].MinTime
   407→	maxt := blocks[0].MaxTime
   408→
   409→	for _, b := range blocks {
   410→		if b.MinTime < mint {
   411→			mint = b.MinTime
   412→		}
   413→		if b.MaxTime > maxt {
   414→			maxt = b.MaxTime
   415→		}
   416→		if b.Compaction.Level > res.Compaction.Level {
   417→			res.Compaction.Level = b.Compaction.Level
   418→		}
   419→		for _, s := range b.Compaction.Sources {
   420→			sources[s] = struct{}{}
   421→		}
   422→		res.Compaction.Parents = append(res.Compaction.Parents, BlockDesc{
   423→			ULID:    b.ULID,
   424→			MinTime: b.MinTime,
   425→			MaxTime: b.MaxTime,
   426→		})
   427→	}
   428→	res.Compaction.Level++
   429→
   430→	for s := range sources {
   431→		res.Compaction.Sources = append(res.Compaction.Sources, s)
   432→	}
   433→	slices.SortFunc(res.Compaction.Sources, func(a, b ulid.ULID) int {
   434→		return a.Compare(b)
   435→	})
   436→
   437→	res.MinTime = mint
   438→	res.MaxTime = maxt
   439→	return res
   440→}
